              <Copy size={14} />
            </button>
          )}
        </header>
      )}
      <div className="markdown-content">
        {blocks.length > 0 ? blocks.map((block, index) => renderMarkdownNode(block, `markdown-${index}`, handleCopy)) : <p>No content.</p>}

